// Arbeitnow — Free EU tech jobs API (no auth needed)
// Strict filter: focus on Junior IT Infrastructure roles

const REQUIRED_TITLE_KEYWORDS = ['administrateur', 'sysadmin', 'devops', 'réseau', 'network engineer', 'cloud', 'infrastructure', 'system administrator'];

const REQUIRED_STACK_KEYWORDS = ['linux', 'windows', 'cisco', 'docker', 'kubernetes', 'aws', 'azure', 'terraform', 'vmware', 'ansible'];

const EXCLUDE_TITLE_KEYWORDS = [
  'copywriter', 'content', 'social media', 'community manager',
  'customer success', 'account manager', 'sales', 'vertrieb',
  'außendienst', 'closer', 'chatsetter', 'country manager',
  'assistenz', 'werkstudent', 'praktikum', 'intern', 'grocery associate'
];

const EXCLUDE_DESC_KEYWORDS = [
  'customer success', 'social media', 'copywriting', 'outbound sales',
  'inside sales', 'field sales', 'account executive', 'business development'
];

function hasAny(text, words) {
  return words.some(w => text.includes(w));
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.arbeitnow.com/api/job-board-api',
    json: true
  });

  const cutoff = Math.floor(Date.now() / 1000) - 3 * 24 * 60 * 60;

  const filtered = (resp.data || []).filter(j => {
    if (j.created_at < cutoff) return false;

    const title = (j.title || '').toLowerCase();
    const desc = (j.description || '').toLowerCase();
    const tags = ((j.tags || []).join(' ') || '').toLowerCase();
    const text = `${title} ${desc} ${tags}`;

    // Hard reject obvious non-target profiles
    if (hasAny(title, EXCLUDE_TITLE_KEYWORDS) || hasAny(desc, EXCLUDE_DESC_KEYWORDS)) return false;

    // Strong accept: explicit target role in title
    if (hasAny(title, REQUIRED_TITLE_KEYWORDS)) return true;

    // Secondary accept: IT stack density + engineering signal in title
    const stackHits = REQUIRED_STACK_KEYWORDS.filter(k => text.includes(k)).length;
    const hasEngineerSignal = /\b(administrateur|engineer|technicien|consultant|ingénieur|sysadmin|devops|support)\b/i.test(title);

    return hasEngineerSignal && stackHits >= 2;
  });

  return [{ json: { data: filtered, count: filtered.length } }];
} catch(e) {
  return [{ json: { data: [], count: 0 } }];
}

// JSearch (RapidAPI) — 500 req/month, 2 queries/run → run every 3h
const hour = new Date().getHours();
if (hour % 3 !== 0) return [{ json: { data: [], count: 0, _skipped: 'JSearch: not scheduled this hour' } }];

const apiKey = $env.RAPIDAPI_KEY;

if (!apiKey) {
  console.log('[JSearch] No RAPIDAPI_KEY set, skipping');
  return [{ json: { data: [], count: 0 } }];
}

// Rotate queries across regions
const regionSets = [
  ['administrateur systeme in France', 'ingénieur reseau in France'],
  ['devops engineer in France', 'cloud engineer in France'],
  ['system administrator in France', 'sysadmin in France'],
  ['technicien informatique in France', 'support IT in France'],
  ['administrateur reseau in France', 'technicien reseau in France'],
  ['cloud architect in France', 'SRE engineer in France'],
  ['ingénieur système in France', 'linux administrator in France'],
  ['windows administrator in France', 'infrastructure engineer in France']
];
const queries = regionSets[Math.floor(hour / 3) % regionSets.length];

const allJobs = [];
for (const q of queries) {
  try {
    const url = `https://jsearch.p.rapidapi.com/search?query=${encodeURIComponent(q)}&page=1&num_pages=1&date_posted=3days`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: {
        'X-RapidAPI-Key': apiKey,
        'X-RapidAPI-Host': 'jsearch.p.rapidapi.com'
      },
      json: true
    });
    if (resp.data) allJobs.push(...resp.data);
  } catch(e) { /* skip */ }
}

return [{ json: { data: allJobs, count: allJobs.length } }];
